const escherFba = (function () {

    const FBC_NS = 'http://www.sbml.org/sbml/level3/version1/fbc/version2';

    function attr(el, name) {
        return el.getAttributeNS(FBC_NS, name)
            || el.getAttribute('fbc:' + name)
            || el.getAttribute(name)
            || null;
    }

    function parseModel(xml) {
        const doc = new DOMParser().parseFromString(xml, 'application/xml');
        if (doc.querySelector('parsererror'))
            throw new Error('SBML XML parse error');

        const species = {};
        doc.querySelectorAll('listOfSpecies > species').forEach(s =>
            species[s.getAttribute('id')] = true);

        const rxns  = [];
        const byId  = {};
        doc.querySelectorAll('listOfReactions > reaction').forEach(el => {
            const id  = el.getAttribute('id');
            const rev = el.getAttribute('reversible') !== 'false';
            const S   = {};

            el.querySelectorAll('listOfReactants > speciesReference').forEach(sr => {
                const sp = sr.getAttribute('species');
                if (sp) S[sp] = (S[sp] || 0) - parseFloat(sr.getAttribute('stoichiometry') || 1);
            });
            el.querySelectorAll('listOfProducts > speciesReference').forEach(sr => {
                const sp = sr.getAttribute('species');
                if (sp) S[sp] = (S[sp] || 0) + parseFloat(sr.getAttribute('stoichiometry') || 1);
            });

            const lbS = attr(el, 'lowerFluxBound');
            const ubS = attr(el, 'upperFluxBound');
            const lb  = lbS !== null ? parseFloat(lbS) : (rev ? -1000 : 0);
            const ub  = ubS !== null ? parseFloat(ubS) : 1000;

            const r = { id, S, lb, ub };
            rxns.push(r);
            byId[id] = r;
        });

        const obj = {};
        doc.querySelectorAll('listOfObjectives objective, objective').forEach(o =>
            o.querySelectorAll('listOfFluxObjectives > fluxObjective, fluxObjective').forEach(fo => {
                const id = attr(fo,'reaction') || fo.getAttribute('reaction');
                const c  = parseFloat(attr(fo,'coefficient') || fo.getAttribute('coefficient') || 1);
                if (id) obj[id] = c;
            }));

        if (!Object.keys(obj).length) {
            const b = rxns.find(r => /biomass/i.test(r.id) || /growth/i.test(r.id));
            if (b) obj[b.id] = 1;
        }

        console.log(`[escherFba] Loaded: ${rxns.length} rxns, ${Object.keys(species).length} species, obj:`, Object.keys(obj));

        return {
            rxns, byId, species, obj,

            setUpperBound(id, v) {
                const r = this.byId[id];
                if (!r) return;
                if (r.lb < 0 && r.ub <= 0) {
                    r.lb = -Math.max(0, v);
                } else {
                    r.ub = Math.max(0, v);
                }
            },

            setLowerBound(id, v) {
                const r = this.byId[id]; if (r) r.lb = v;
            },

            reset() {
            }
        };
    }

    function solve(model) {
        const { rxns, species, obj } = model;
        const spp = Object.keys(species);

        if (!rxns.length) return { objectiveValue: 0, fluxes: {}, status: 'empty' };

        const lp = { optimize: '_obj', opType: 'max', constraints: {}, variables: {} };

        spp.forEach(sp => { lp.constraints['mb_' + sp] = { equal: 0 }; });

        rxns.forEach(r => {
            const maxFwd = Math.max(0, isFinite(r.ub) ? r.ub : 1000);
            const maxRev = Math.max(0, isFinite(r.lb) ? -r.lb : 0);

            const fDef = {};
            if (obj[r.id])  fDef._obj = obj[r.id];
            spp.forEach(sp => { if (r.S[sp]) fDef['mb_' + sp] = r.S[sp]; });
            if (maxFwd <= 999) {
                lp.constraints['ub_' + r.id + '_f'] = { max: maxFwd };
                fDef['ub_' + r.id + '_f'] = 1;
            }
            lp.variables[r.id + '_f'] = fDef;

            if (maxRev > 0) {
                const rDef = {};
                if (obj[r.id]) rDef._obj = -obj[r.id];
                spp.forEach(sp => { if (r.S[sp]) rDef['mb_' + sp] = -r.S[sp]; });
                lp.constraints['ub_' + r.id + '_r'] = { max: maxRev };
                rDef['ub_' + r.id + '_r'] = 1;
                lp.variables[r.id + '_r'] = rDef;
            }
        });

        if (lp.constraints['ub_BIOMASS_f']) {
            lp.constraints['ub_BIOMASS_f'].min = 0.0001;
        }
        let res;
        try { res = window.solver.Solve(lp); }
        catch(e) { console.error('[escherFba] Solver error:', e); return { objectiveValue: 0, fluxes: {}, status: 'error' }; }

        const z = res.result || 0;
        const fluxes = {};
        rxns.forEach(r => { fluxes[r.id] = (res[r.id+'_f']||0) - (res[r.id+'_r']||0); });

        console.log(`[escherFba] FBA: obj=${z.toFixed(4)} feasible=${res.feasible} BIOMASS=${(fluxes.BIOMASS||0).toFixed(4)}`);

        const biomassFlux = (res['BIOMASS_f'] || 0) - (res['BIOMASS_r'] || 0);
        const effectiveObj = z > 0 ? z : biomassFlux;
        return { objectiveValue: effectiveObj, fluxes, status: res.feasible ? 'optimal' : 'suboptimal' };
    }

    return {
        loadModel: parseModel,
        solve: (model, _solver) => solve(model),
    };
})();

window.glpk = () => Promise.resolve({
    GLP_MIN:1, GLP_MAX:2, GLP_FR:1, GLP_LO:2, GLP_UP:3, GLP_DB:4, GLP_FX:5,
    GLP_MSG_OFF:0, GLP_OPT:5, GLP_NOFEAS:4, GLP_UNBND:6, GLP_UNDEF:1,
    solve: () => ({ result: { z:0, vars:{}, status:5 } }),
    version: 'jsLPSolver-shim',
});
console.log('[GEMgen] escherFba ready (jsLPSolver backend)');
